-- ============================================================================
-- ALIGNMENT GYM #1 RECAP EMAIL
--
-- Recap email for the first Alignment Gym session (April 1, 2025).
-- Personal-style follow-up with replay link, key shifts, member win,
-- and action steps. Manual CRM blast to Activation Intensive graduates.
-- ============================================================================

INSERT INTO email_templates (slug, name, description, category, status, subject, html_body, text_body, variables, triggers)
VALUES (
  'alignment-gym-recap-1',
  'Alignment Gym #1: Recap Email',
  'Recap email for the first Alignment Gym session. Includes replay link, key shifts, member win, action steps, and next session details.',
  'marketing',
  'active',

  -- SUBJECT
  E'Alignment Gym #1: Replay + This Week''s Shift',

  -- HTML BODY (personal style — matches launch email aesthetic)
  E'<!DOCTYPE html>\n<html lang="en">\n<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head>\n<body style="margin:0;padding:0;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',Roboto,''Helvetica Neue'',Arial,sans-serif;background-color:#ffffff;color:#333333;">\n<table width="100%" cellpadding="0" cellspacing="0" style="background-color:#ffffff;"><tr><td align="center" style="padding:40px 20px;">\n<table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;text-align:left;">\n<tr><td style="font-size:16px;line-height:1.6;color:#333333;">\n\n<p style="margin:0 0 10px;">Hey Vibe Tribe,</p>\n\n<p style="margin:0 0 10px;">What a way to kick off our very first Alignment Gym.</p>\n\n<p style="margin:0 0 10px;">First, thank you.<br>\nThis room is invite-only for Activation Intensive graduates, and the fact that we had 100% participation says everything about the kind of creators you are.</p>\n\n<p style="margin:0 0 10px;">If you couldn''t be there live (or want to re-immerse), watch the replay here:</p>\n\n<p style="margin:0 0 20px;"><a href="https://vibrationfit.com/alignment-gym/ebf53904-1a74-4351-ade3-ebe8dac4dc0e" style="color:#1a73e8;text-decoration:none;">https://vibrationfit.com/alignment-gym/ebf53904-1a74-4351-ade3-ebe8dac4dc0e</a></p>\n\n<!-- This Week''s Shifts -->\n<p style="margin:0 0 6px;font-size:20px;"><strong>This Week''s Shifts</strong></p>\n\n<p style="margin:0 0 6px;"><strong>1. You''re Now Playing a Different Game</strong></p>\n<p style="margin:0 0 14px;">You''re no longer just &ldquo;learning&rdquo; this work, you''re living it. The Alignment Gym is where we go deeper, refine your tools, and turn awareness into actual life change.</p>\n\n<p style="margin:0 0 6px;"><strong>2. Above the Green Line = Alignment</strong></p>\n<p style="margin:0 0 14px;">Above the Green Line, you are in harmony with your higher, non-physical self.<br>\nBelow the Green Line, you''re focusing in a way that''s out of alignment.<br>\nYour emotions aren''t problems; they''re real-time guidance.</p>\n\n<p style="margin:0 0 6px;"><strong>3. You Don''t Jump&hellip; You Climb</strong></p>\n<p style="margin:0 0 14px;">You don''t go from &ldquo;I feel terrible&rdquo; to &ldquo;I feel amazing&rdquo; in one leap.<br>\nYou reach for a thought that feels slightly better, which unlocks better thoughts, and you spiral upward. This is how real transformation actually works.</p>\n\n<p style="margin:0 0 6px;"><strong>4. VIVA Is Your Bridge Back to Alignment</strong></p>\n<p style="margin:0 0 14px;">When you''re below the Green Line, you don''t have access to your clarity.<br>\nVIVA reflects your highest perspective, flips contrast into clarity, and shows you what your aligned self sees so you can come back up.</p>\n\n<p style="margin:0 0 6px;"><strong>5. Your Life Vision Is the Filter</strong></p>\n<p style="margin:0 0 14px;">Your Life Vision is now your filter for decisions.<br>\nAsk: &ldquo;Is this in my vision?&rdquo;<br>\nIf yes, move toward it. If no, it''s not your path. This eliminates confusion and decision fatigue.</p>\n\n<!-- Member Win -->\n<table width="100%" cellpadding="0" cellspacing="0" style="margin:20px 0;"><tr><td style="border-left:4px solid #199D67;padding:16px 20px;background-color:#f9f9f9;border-radius:0 8px 8px 0;">\n<p style="margin:0 0 6px;font-size:18px;color:#199D67;"><strong>Member Win of the Week</strong></p>\n<p style="margin:0 0 8px;font-style:italic;">This week''s win is from Barbara in Texas:</p>\n<p style="margin:0 0 8px;font-style:italic;color:#555555;">&ldquo;One of the things I had mentioned in my Life Vision is that we had a lake house where my husband could fish. Well, a couple of days later after listening to it I took the lake house out. I decided that I really didn''t want one. This past Sunday some friends of ours came over to visit on our deck. (Friends visiting on the deck is within my vision.) They told us of a vacation to the Smokey mountains in Tennessee that they were planning. They were staying in a cabin at a lake to fish. Would we like to join them? Of course, we said YES! I''ve talked with her again to start working out the details. It''s a big win.&rdquo;</p>\n<p style="margin:0;color:#333333;">Big win, Barbara. This is exactly what happens when you get crystal clear on your Life Vision and stay above the Green Line: life starts rearranging to match it.</p>\n</td></tr></table>\n\n<p style="margin:0 0 10px;">If you want to read her full post or add some love, it''s inside the Vibe Tribe community.</p>\n\n<!-- Action Steps -->\n<p style="margin:0 0 6px;font-size:20px;"><strong>Action Steps This Week</strong></p>\n<p style="margin:0 0 6px;">This week, focus on implementing, not overthinking:</p>\n<ul style="margin:0 0 16px;padding-left:24px;">\n  <li style="margin-bottom:4px;">Activate your Life Vision daily</li>\n  <li style="margin-bottom:4px;">Notice when you''re below the Green Line (no judgment)</li>\n  <li style="margin-bottom:4px;">Reach for slightly better-feeling thoughts</li>\n  <li style="margin-bottom:4px;">Use your vision as a decision filter</li>\n  <li style="margin-bottom:4px;">Track moments of alignment and synchronicity</li>\n</ul>\n\n<!-- Next Session -->\n<p style="margin:0 0 6px;font-size:20px;"><strong>Next Alignment Gym</strong></p>\n<p style="margin:0 0 6px;">Our next Alignment Gym is on:</p>\n<p style="margin:0 0 10px;font-size:18px;"><strong>Tuesday, April 7th at 12pm ET</strong></p>\n<p style="margin:0 0 16px;">We''ll go deeper into applying the Green Line and VIVA to core life areas: body, money, relationships, and career, plus live coaching and member spotlights. Add it to your calendar now.</p>\n\n<!-- Closing -->\n<p style="margin:0 0 6px;font-size:20px;"><strong>Final Thought</strong></p>\n<p style="margin:0 0 10px;">You already have everything you need.<br>\nNow it''s about practicing alignment until it becomes your default.</p>\n\n<p style="margin:0 0 2px;">We love you guys.<br>\nAnd we''re just getting started.</p>\n\n<p style="margin:16px 0 0;">&mdash; Jordan &amp; Vanessa</p>\n\n</td></tr>\n</table></td></tr></table>\n</body></html>',

  -- TEXT BODY
  E'Hey Vibe Tribe,\n\nWhat a way to kick off our very first Alignment Gym.\n\nFirst, thank you.\nThis room is invite-only for Activation Intensive graduates, and the fact that we had 100% participation says everything about the kind of creators you are.\n\nIf you couldn''t be there live (or want to re-immerse), watch the replay here:\nhttps://vibrationfit.com/alignment-gym/ebf53904-1a74-4351-ade3-ebe8dac4dc0e\n\n\nThis Week''s Shifts\n\n1. You''re Now Playing a Different Game\nYou''re no longer just "learning" this work, you''re living it. The Alignment Gym is where we go deeper, refine your tools, and turn awareness into actual life change.\n\n2. Above the Green Line = Alignment\nAbove the Green Line, you are in harmony with your higher, non-physical self.\nBelow the Green Line, you''re focusing in a way that''s out of alignment.\nYour emotions aren''t problems; they''re real-time guidance.\n\n3. You Don''t Jump... You Climb\nYou don''t go from "I feel terrible" to "I feel amazing" in one leap.\nYou reach for a thought that feels slightly better, which unlocks better thoughts, and you spiral upward. This is how real transformation actually works.\n\n4. VIVA Is Your Bridge Back to Alignment\nWhen you''re below the Green Line, you don''t have access to your clarity.\nVIVA reflects your highest perspective, flips contrast into clarity, and shows you what your aligned self sees so you can come back up.\n\n5. Your Life Vision Is the Filter\nYour Life Vision is now your filter for decisions.\nAsk: "Is this in my vision?"\nIf yes, move toward it. If no, it''s not your path. This eliminates confusion and decision fatigue.\n\n\nMember Win of the Week\n\nThis week''s win is from Barbara in Texas:\n\n"One of the things I had mentioned in my Life Vision is that we had a lake house where my husband could fish. Well, a couple of days later after listening to it I took the lake house out. I decided that I really didn''t want one. This past Sunday some friends of ours came over to visit on our deck. (Friends visiting on the deck is within my vision.) They told us of a vacation to the Smokey mountains in Tennessee that they were planning. They were staying in a cabin at a lake to fish. Would we like to join them? Of course, we said YES! I''ve talked with her again to start working out the details. It''s a big win."\n\nBig win, Barbara. This is exactly what happens when you get crystal clear on your Life Vision and stay above the Green Line: life starts rearranging to match it.\n\nIf you want to read her full post or add some love, it''s inside the Vibe Tribe community.\n\n\nAction Steps This Week\n\nThis week, focus on implementing, not overthinking:\n\n- Activate your Life Vision daily\n- Notice when you''re below the Green Line (no judgment)\n- Reach for slightly better-feeling thoughts\n- Use your vision as a decision filter\n- Track moments of alignment and synchronicity\n\n\nNext Alignment Gym\n\nOur next Alignment Gym is on:\nTuesday, April 7th at 12pm ET\n\nWe''ll go deeper into applying the Green Line and VIVA to core life areas: body, money, relationships, and career, plus live coaching and member spotlights. Add it to your calendar now.\n\n\nFinal Thought\n\nYou already have everything you need.\nNow it''s about practicing alignment until it becomes your default.\n\nWe love you guys.\nAnd we''re just getting started.\n\n-- Jordan & Vanessa',

  '[]'::jsonb,
  '["Manual CRM blast to Activation Intensive graduates after Alignment Gym #1"]'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name, description = EXCLUDED.description, category = EXCLUDED.category,
  status = EXCLUDED.status, subject = EXCLUDED.subject, html_body = EXCLUDED.html_body,
  text_body = EXCLUDED.text_body, variables = EXCLUDED.variables,
  triggers = EXCLUDED.triggers, updated_at = NOW();
